import type { DMMF } from '@prisma/dmmf'

import { mapScalarType } from './type-mapping'

/**
 * Returns the TypeScript type string for a single DMMF field, respecting list
 * and nullability modifiers.
 */
function fieldTsType(field: DMMF.Field): string {
  let base: string

  if (field.kind === 'scalar') {
    base = mapScalarType(field.type)
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    // Relation and unsupported fields are represented as the related model name
    base = field.type
  }

  return field.isList ? `${base}[]` : base
}

/**
 * Returns true for fields that should be included in the base model interface —
 * every non-object field (scalars and enums). Relation fields are omitted because
 * they are not part of the scalar REST payload.
 */
function isScalarOrEnum(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/**
 * Returns true for fields that are writable in create/update operations:
 * scalar/enum, not read-only, and not auto-generated by the database.
 */
function isWritable(field: DMMF.Field): boolean {
  return isScalarOrEnum(field) && !field.isReadOnly && !field.isGenerated
}

/**
 * Returns true for fields required in a create payload: writable, required,
 * and without a server-side default (e.g. @default).
 */
function isRequiredInCreate(field: DMMF.Field): boolean {
  return isWritable(field) && field.isRequired && !field.hasDefaultValue && !field.isId
}

/**
 * Generates the four TypeScript interfaces for a single Prisma model:
 *
 * - `${Model}` — the complete model shape returned by the API.
 * - `${Model}CreateInput` — payload for creating a new record.
 * - `${Model}UpdateInput` — partial payload for updating an existing record.
 * - `${Model}WhereUniqueInput` — identifies a unique record (id / unique fields).
 */
export function generateModelInterface(model: DMMF.Model, enums: readonly DMMF.DatamodelEnum[]): string {
  const enumNames = new Set(enums.map((e) => e.name))
  const lines: string[] = []

  // ── Base model interface ────────────────────────────────────────────────────

  lines.push(`export interface ${model.name} {`)
  for (const field of model.fields) {
    if (!isScalarOrEnum(field)) continue
    const optional = !field.isRequired ? '?' : ''
    const tsType = fieldTsType(field)
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }
  lines.push('}')
  lines.push('')

  // ── Enum re-exports (inline union if the enum is defined in the schema) ────

  for (const field of model.fields) {
    if (field.kind !== 'enum' || !enumNames.has(field.type)) continue
    // Only emit once per enum type referenced by this model
  }

  // ── CreateInput ────────────────────────────────────────────────────────────

  lines.push(`export interface ${model.name}CreateInput {`)
  for (const field of model.fields) {
    if (!isWritable(field)) continue
    const required = isRequiredInCreate(field)
    const optional = required ? '' : '?'
    const tsType = fieldTsType(field)
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }
  lines.push('}')
  lines.push('')

  // ── UpdateInput ────────────────────────────────────────────────────────────

  lines.push(`export interface ${model.name}UpdateInput {`)
  for (const field of model.fields) {
    if (!isWritable(field)) continue
    const tsType = fieldTsType(field)
    lines.push(`  ${field.name}?: ${tsType}`)
  }
  lines.push('}')
  lines.push('')

  // ── WhereUniqueInput ───────────────────────────────────────────────────────

  lines.push(`/** Provide exactly one field to identify a unique ${model.name}. */`)
  lines.push(`export interface ${model.name}WhereUniqueInput {`)
  for (const field of model.fields) {
    if (!isScalarOrEnum(field)) continue
    if (!field.isId && !field.isUnique) continue
    const tsType = fieldTsType(field)
    lines.push(`  ${field.name}?: ${tsType}`)
  }
  lines.push('}')

  return lines.join('\n') + '\n'
}

